    // .NET 9 breaking change: GetEnvironmentVariable now returns null
    // for empty env vars on Unix (previously returned "").
    // Use IsEnvironmentVariableSet to distinguish "not set" from "empty".
    if (!IsEnvironmentVariableSet("MY_FLAG"))
    {
        Console.WriteLine("MY_FLAG not set, using default");
    }
}

static bool IsEnvironmentVariableSet(string variable)
{
    // Checks /proc/self/environ to detect vars that exist but are empty,
    // since .NET 9 collapses "" to null on Unix.
    var environ = File.ReadAllText("/proc/self/environ");
    return environ.Split('\0').Any(e => e.StartsWith(variable + "="));
}

